import pika
import subprocess
import json
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class JobConsumer:
    def __init__(self, host='localhost', queue_name='job_queue'):
        self.host = host
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def process_message(self, ch, method, properties, body):
        try:
            logger.info(f"Received message: {body}")
            
            message = json.loads(body)
            command = message.get('command', '')
            
            if not command:
                logger.error("No command found in message")
                ch.basic_ack(delivery_tag=method.delivery_tag)
                return
            
            logger.info(f"Executing command: {command}")
            
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=300
            )
            
            logger.info(f"Command executed with return code: {result.returncode}")
            logger.info(f"STDOUT: {result.stdout}")
            
            if result.stderr:
                logger.error(f"STDERR: {result.stderr}")
            
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
        except json.JSONDecodeError:
            logger.error("Failed to decode JSON message")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except subprocess.TimeoutExpired:
            logger.error("Command execution timed out")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
    
    def start_consuming(self):
        self.connect()
        self.channel.basic_qos(prefetch_count=1)
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.process_message
        )
        
        logger.info(f"Starting to consume messages from {self.queue_name}")
        self.channel.start_consuming()
    
    def close(self):
        if self.connection and not self.connection.is_closed:
            self.connection.close()


if __name__ == '__main__':
    consumer = JobConsumer(host='localhost', queue_name='job_queue')
    try:
        consumer.start_consuming()
    except KeyboardInterrupt:
        logger.info("Shutting down consumer")
        consumer.close()